#!/bin/bash

# Update Gateway API CRDs.
# Currently we only manage GRPCRoute here, as other Gateway API CRDs (Gateway, HTTPRoute, etc.)
# are installed and managed by GKE's standard gateway_api_config addon.

GATEWAY_API_VERSION=1.1.0

SCRIPT_DIR=$( cd -- "$( dirname -- "${BASH_SOURCE[0]}" )" &> /dev/null && pwd )
dst="${SCRIPT_DIR}/grpcroute-generated.yaml"

echo "Downloading Gateway API GRPCRoute CRD v${GATEWAY_API_VERSION}..."
{
  echo "# Generated by update-gateway.sh. DO NOT EDIT!"
  echo "# ---------------------------------------------------------"
  echo "# Gateway API GRPCRoute CRD (Standard Channel v${GATEWAY_API_VERSION})"
  echo "# ---------------------------------------------------------"
  curl -fsSL "https://raw.githubusercontent.com/kubernetes-sigs/gateway-api/v${GATEWAY_API_VERSION}/config/crd/standard/gateway.networking.k8s.io_grpcroutes.yaml"
} > "${dst}"

echo "Updated ${dst}"
